/**
 * Default cap for [`FlateDecoder`]: 256 MB per stream.
 *
 * Prevents zip-bomb / flate-bomb attacks where a tiny compressed stream
 * expands to an arbitrarily large output, exhausting virtual memory and
 * triggering an allocator abort (SIGABRT / exit 134).
 *
 * 256 MB accommodates A4 @ 600 DPI RGB (~99 MB) with headroom.
 *
 * Override via:
 * - `PDF_OXIDE_MAX_DECOMPRESS_MB` environment variable (e.g. `64` for 64 MB)
 * - [`FlateDecoder::with_limit`] for programmatic control
 */
#define DEFAULT_MAX_DECOMPRESSED_BYTES ((256 * 1024) * 1024)

/**
 * Maximum nested `{ ... }` depth permitted by the parser. PLRM has no formal
 * cap, but real-world Type 4 streams are shallow; bounding it prevents a
 * maliciously deep stream from blowing the Rust call stack since `parse_body`
 * recurses for each brace level. Programs nested deeper return
 * [`Error::InvalidPdf`].
 */
#define MAX_PARSE_DEPTH 32

/**
 * Maximum operand stack size during execution. PLRM §7.10.5.2 requires a
 * "stack overflow" diagnostic; we surface it as [`Error::Type4Runtime`]. The
 * cap matches what Adobe accepts in practice — Acrobat's interpreter allows
 * up to a few hundred operands.
 */
#define MAX_STACK 256

/**
 * Maximum number of instructions the evaluator will execute. Type 4 has no
 * loops in the language proper, but nested `if`/`ifelse` plus large generated
 * bodies (or pathological streams crafted to consume CPU) can still produce
 * arbitrarily many steps. 100 000 is generous for any realistic tint
 * transform while still being a hard upper bound. Programs that exceed this
 * budget return [`Error::Type4Runtime`].
 */
#define MAX_INSTRUCTIONS 100000

/**
 * Field is read-only (bit 1)
 */
#define READ_ONLY 1

/**
 * Field is required (bit 2)
 */
#define REQUIRED (1 << 1)

/**
 * Field should not be exported (bit 3)
 */
#define NO_EXPORT (1 << 2)

/**
 * Text field allows multiple lines (bit 13)
 */
#define MULTILINE (1 << 12)

/**
 * Text field is a password field (bit 14)
 */
#define PASSWORD (1 << 13)

/**
 * Text field does not scroll (bit 24)
 */
#define DO_NOT_SCROLL (1 << 23)

/**
 * Text field allows comb formatting (bit 25)
 */
#define COMB (1 << 24)

/**
 * Text field is a rich text field (bit 26)
 */
#define RICH_TEXT (1 << 25)

/**
 * Button is a push button (bit 17)
 */
#define PUSH_BUTTON (1 << 16)

/**
 * Radio button (bit 16)
 */
#define RADIO (1 << 15)

/**
 * Radio buttons in group are exclusive (bit 26)
 */
#define RADIOS_IN_UNISON (1 << 25)

/**
 * Choice is a combo box (bit 18)
 */
#define COMBO (1 << 17)

/**
 * Choice field is editable (bit 19)
 */
#define EDIT (1 << 18)

/**
 * Choice field is sorted (bit 20)
 */
#define SORT (1 << 19)

/**
 * Choice field allows multiple selection (bit 22)
 */
#define MULTI_SELECT (1 << 21)

/**
 * Do not spell check (bit 23)
 */
#define DO_NOT_SPELL_CHECK (1 << 22)

/**
 * Commit on change (bit 27)
 */
#define COMMIT_ON_SEL_CHANGE (1 << 26)

/**
 * Invisible flag (bit 1) - If set, do not display if no AP.
 */
#define AnnotationFlags_INVISIBLE (1 << 0)

/**
 * Hidden flag (bit 2) - If set, do not display or print.
 */
#define AnnotationFlags_HIDDEN (1 << 1)

/**
 * Print flag (bit 3) - If set, print annotation when printing.
 */
#define AnnotationFlags_PRINT (1 << 2)

/**
 * NoZoom flag (bit 4) - If set, do not scale with page zoom.
 */
#define AnnotationFlags_NO_ZOOM (1 << 3)

/**
 * NoRotate flag (bit 5) - If set, do not rotate with page.
 */
#define AnnotationFlags_NO_ROTATE (1 << 4)

/**
 * NoView flag (bit 6) - If set, do not display on screen.
 */
#define AnnotationFlags_NO_VIEW (1 << 5)

/**
 * ReadOnly flag (bit 7) - If set, do not allow interaction.
 */
#define AnnotationFlags_READ_ONLY (1 << 6)

/**
 * Locked flag (bit 8) - If set, do not allow deletion/modification.
 */
#define AnnotationFlags_LOCKED (1 << 7)

/**
 * ToggleNoView flag (bit 9) - Invert NoView on mouse events.
 */
#define AnnotationFlags_TOGGLE_NO_VIEW (1 << 8)

/**
 * LockedContents flag (bit 10) - If set, do not allow content modification.
 */
#define AnnotationFlags_LOCKED_CONTENTS (1 << 9)

/**
 * Maximum slug length in bytes (keeps total paths well under the
 * 255-byte component limit common to ext4/APFS/NTFS).
 */
#define DEFAULT_MAX_SLUG_BYTES 80

/**
 * Default minimum edge padding, in points — the `0.5pt` floor that keeps an
 * anti-aliased glyph sliver from surviving at a region boundary
 * (feature plan §4.1).
 */
#define DEFAULT_EDGE_PADDING 0.5

/**
 * Y-band tolerance used by `row_aware_span_cmp`.
 *
 * Two spans whose top-Y differs by less than this amount are treated
 * as lying on the same row. Chosen to absorb typographic baseline
 * jitter for 10-12pt body text and glyph-cluster offsets in CJK
 * fonts without merging adjacent 14pt-leading lines.
 */
#define ROW_BAND_TOLERANCE_PT 3.0

