/**
 * A high-level PDF document with unified DOM access.
 *
 * This type provides a simple, unified API for:
 * - Creating PDFs from Markdown, HTML, or plain text
 * - Opening existing PDFs for reading and editing
 * - Navigating the document structure with a DOM-like API
 * - Modifying text, images, and other content
 * - Saving changes back to PDF
 *
 * # Example
 *
 * ```ignore
 * use pdf_oxide::api::Pdf;
 *
 * // Create from Markdown
 * let pdf = Pdf::from_markdown("# Hello")?;
 * pdf.save("hello.pdf")?;
 *
 * // Open and edit existing PDF
 * let mut doc = Pdf::open("input.pdf")?;
 * let page = doc.page(0)?;
 * for text in page.find_text_containing("old") {
 *     doc.page(0)?.set_text(text.id(), "new")?;
 * }
 * doc.save("output.pdf")?;
 * ```
 */
typedef struct Pdf Pdf;

/**
 * PDF document.
 *
 * This structure represents an open PDF document, providing access to:
 * - Document metadata (version, catalog, trailer)
 * - Page information (count, page tree)
 * - Object loading and dereferencing
 *
 * # Example
 *
 * ```no_run
 * use pdf_oxide::document::PdfDocument;
 *
 * let mut doc = PdfDocument::open("sample.pdf")?;
 * println!("PDF version: {}.{}", doc.version().0, doc.version().1);
 * println!("Page count: {}", doc.page_count()?);
 * # Ok::<(), pdf_oxide::error::Error>(())
 * ```
 *
 * # Memory management
 *
 * The document maintains several internal caches for performance. The main
 * object cache is bounded at 64 MB (see `DEFAULT_OBJECT_CACHE_MAX_BYTES`)
 * uses FIFO eviction to prevent unbounded heap growth when processing
 * many pages sequentially.
 */
typedef struct PdfDocument PdfDocument;

/**
 * Per-CID vertical-writing metrics from a CIDFont's `/W2` array.
 *
 * Per ISO 32000-1:2008 §9.7.4.3 and the Adobe CMap & CIDFont Files
 * Specification §9.7. In vertical writing mode the glyph advances along the
 * y-axis (not the x-axis) and is shifted from its default horizontal origin
 * to a vertical origin so that the glyph stacks correctly within a column.
 *
 * All values are in 1000ths-of-em (glyph-space units), matching the
 * convention used throughout PDF font dictionaries.
 */
typedef struct VerticalMetrics VerticalMetrics;

#if !defined(PDF_OXIDE_TARGET_WASM32)
/**
 * Options for [`pdf_sign_bytes_pades_opts`] — the same parameters as
 * [`pdf_sign_bytes_pades`], collapsed into one `#[repr(C)]` struct.
 *
 * `pdf_sign_bytes_pades` takes 18 scalar arguments, which exceeds the
 * argument-marshalling limit of some FFI clients (notably the pure-Go
 * `purego` backend on the SysV/AMD64 ABI, which panics at registration
 * above ~9 arguments). This struct-pointer variant keeps the call
 * surface at 5 arguments so every binding — including `CGO_ENABLED=0`
 * Go — can invoke PAdES signing. Field order/types mirror the scalar
 * function exactly; `#[repr(C)]` makes the layout match a C struct of
 * the same fields on every supported platform.
 */
typedef struct {
    const void *certificate_handle;
    const uint8_t *const *certs;
    const uintptr_t *cert_lens;
    uintptr_t n_certs;
    const uint8_t *const *crls;
    const uintptr_t *crl_lens;
    uintptr_t n_crls;
    const uint8_t *const *ocsps;
    const uintptr_t *ocsp_lens;
    uintptr_t n_ocsps;
    const char *tsa_url;
    const char *reason;
    const char *location;
    int32_t level;
} PadesSignOptionsC;
#endif

